// worker1.js - Public-facing worker
export default {
  async fetch(request, env) {
    try {
      const url = new URL(request.url);
      const path = url.pathname;
      
      // Route to appropriate internal worker
      if (path.startsWith('/api/users')) {
        return await env.USERS_WORKER.fetch(request);
      } else if (path.startsWith('/api/orders')) {
        return await env.ORDERS_WORKER.fetch(request);
      } else if (path.startsWith('/api/products')) {
        return await env.PRODUCTS_WORKER.fetch(request);
      } else {
        return new Response('Service not found', { status: 404 });
      }
    } catch (error) {
      return new Response('Internal Server Error', { status: 500 });
    }
  }
};

// worker2.js - Users internal worker
export default {
  async fetch(request, env) {
    try {
      const url = new URL(request.url);
      const method = request.method;
      
      // Security: Validate request
      if (!isValidRequest(request, env)) {
        return new Response('Unauthorized', { status: 401 });
      }
      
      // Process user requests
      if (method === 'GET' && url.pathname.includes('/users/')) {
        const userId = url.pathname.split('/').pop();
        const user = await env.DB.prepare('SELECT * FROM users WHERE id = ?').bind(userId).first();
        return new Response(JSON.stringify(user), { headers: { 'Content-Type': 'application/json' } });
      } else if (method === 'POST' && url.pathname === '/users') {
        const userData = await request.json();
        const result = await env.DB.prepare('INSERT INTO users (name, email) VALUES (?, ?) RETURNING *').bind(userData.name, userData.email).first();
        return new Response(JSON.stringify(result), { status: 201, headers: { 'Content-Type': 'application/json' } });
      }
      
      return new Response('Method not allowed', { status: 405 });
    } catch (error) {
      return new Response('Internal Server Error', { status: 500 });
    }
  }
};

